+// Pipe-only words are otherwise legal identifiers. Promote them only in their
+// pipe context so traditional BigQuery statements retain their tokenization.
+function detectPipeClauses(tokens: Token[]): Token[] {
+  let inAggregate = false;
+  return tokens.map((token, index) => {
+    if (token.type === TokenType.PIPE_OPERATOR) {
+      inAggregate = tokens[index + 1]?.text === 'AGGREGATE';
